contracts/core/KycManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { AccessControlEnumerableUpgradeable } from "@openzeppelin/contracts-upgradeable/access/extensions/AccessControlEnumerableUpgradeable.sol";
import { UUPSUpgradeable } from "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";

/// @title KycManager
/// @notice Single source of truth for KYC across HYBOND Token and Express.
contract KycManager is AccessControlEnumerableUpgradeable, UUPSUpgradeable {
    bytes32 public constant WHITELIST_ROLE = keccak256("WHITELIST_ROLE");

    mapping(address => bool) private _kycList;

    event KycGranted(address indexed account);
    event KycRevoked(address indexed account);

    error InvalidAddress();
    error AlreadyKyced(address account);
    error NotKyced(address account);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address admin) public initializer {
        if (admin == address(0)) revert InvalidAddress();
        __AccessControlEnumerable_init();
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
    }

    function grantKyc(address account) external onlyRole(WHITELIST_ROLE) {
        _grantKyc(account);
    }

    function revokeKyc(address account) external onlyRole(WHITELIST_ROLE) {
        _revokeKyc(account);
    }

    function grantKycBulk(address[] calldata accounts) external onlyRole(WHITELIST_ROLE) {
        uint256 length = accounts.length;
        for (uint256 i; i < length; ) {
            _grantKyc(accounts[i]);
            unchecked {
                ++i;
            }
        }
    }

    function revokeKycBulk(address[] calldata accounts) external onlyRole(WHITELIST_ROLE) {
        uint256 length = accounts.length;
        for (uint256 i; i < length; ) {
            _revokeKyc(accounts[i]);
            unchecked {
                ++i;
            }
        }
    }

    function isKyced(address account) external view returns (bool) {
        return _kycList[account];
    }

    function _grantKyc(address account) private {
        if (account == address(0)) revert InvalidAddress();
        if (_kycList[account]) revert AlreadyKyced(account);
        _kycList[account] = true;
        emit KycGranted(account);
    }

    function _revokeKyc(address account) private {
        if (!_kycList[account]) revert NotKyced(account);
        _kycList[account] = false;
        emit KycRevoked(account);
    }

    function _authorizeUpgrade(address) internal override onlyRole(DEFAULT_ADMIN_ROLE) {}

    uint256[49] private __gap;
}

contracts/core/Token.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { ERC20Upgradeable } from "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";
import { ERC20PausableUpgradeable } from "@openzeppelin/contracts-upgradeable/token/ERC20/extensions/ERC20PausableUpgradeable.sol";
import { AccessControlEnumerableUpgradeable } from "@openzeppelin/contracts-upgradeable/access/extensions/AccessControlEnumerableUpgradeable.sol";
import { UUPSUpgradeable } from "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";
import { IKycManager } from "../interfaces/IKycManager.sol";

/**
 * @title Token
 * @dev Standard ERC-20 upgradeable for single-chain deployment
 *
 * Key Features:
 * - Built-in AccessControlEnumerable for role management
 * - Issue cap (maximum supply limit)
 * - Ban list enforcement on all transfers
 * - Burnable tokens
 * - Pausable for emergency situations
 * - Upgradeable via UUPS pattern
 */
contract Token is ERC20Upgradeable, ERC20PausableUpgradeable, AccessControlEnumerableUpgradeable, UUPSUpgradeable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    bytes32 public constant PAUSE_ROLE = keccak256("PAUSE_ROLE");
    bytes32 public constant BANLIST_ROLE = keccak256("BANLIST_ROLE");
    bytes32 public constant UPGRADE_ROLE = keccak256("UPGRADE_ROLE");

    uint256 public issueCap;
    mapping(address => bool) private _bannedList;
    address public kycManager;

    event Mint(address indexed to, uint256 amount);
    event Burn(address indexed from, uint256 amount);
    event IssueCapUpdated(uint256 oldCap, uint256 newCap);
    event AccountBanned(address indexed addr);
    event AccountUnbanned(address indexed addr);
    event KycManagerUpdated(address indexed oldManager, address indexed newManager);

    error InvalidAddress();
    error InvalidAmount();
    error ExceedsIssueCap();
    error CapBelowSupply();
    error BannedSender(address sender);
    error BannedRecipient(address recipient);
    error InvalidBannedAccount(address account);
    error BatchSizeTooLarge();
    error NotKyced(address account);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    /**
     * @notice Initialize the token
     * @param _name Token name
     * @param _symbol Token symbol
     * @param _admin Default admin address
     * @param _issueCap Maximum supply limit (0 = unlimited)
     * @param _kycManager KYC manager address (address(0) = permissionless mode)
     */
    function initialize(
        string memory _name,
        string memory _symbol,
        address _admin,
        uint256 _issueCap,
        address _kycManager
    ) public initializer {
        __ERC20_init(_name, _symbol);
        __ERC20Pausable_init();
        __AccessControlEnumerable_init();

        if (_admin == address(0)) revert InvalidAddress();

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        issueCap = _issueCap;
        kycManager = _kycManager;
    }

    /**
     * @notice Mint new tokens
     * @param to Recipient address
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        if (amount == 0) revert InvalidAmount();

        uint256 _issueCap = issueCap;
        if (_issueCap > 0) {
            if (totalSupply() + amount > _issueCap) revert ExceedsIssueCap();
        }

        _mint(to, amount);
        emit Mint(to, amount);
    }

    /**
     * @notice Burn tokens
     * @param amount Amount to burn
     */
    function burn(address from, uint256 amount) external onlyRole(BURNER_ROLE) {
        if (amount == 0) revert InvalidAmount();

        _burn(from, amount);
        emit Burn(from, amount);
    }

    /**
     * @notice Increase the allowance granted to spender
     * @param spender The address which will spend the funds
     * @param addedValue The amount to increase the allowance by
     * @return True if the operation succeeded
     */
    function increaseAllowance(address spender, uint256 addedValue) external returns (bool) {
        address owner = _msgSender();
        _approve(owner, spender, allowance(owner, spender) + addedValue);
        return true;
    }

    /**
     * @notice Decrease the allowance granted to spender
     * @param spender The address which will spend the funds
     * @param subtractedValue The amount to decrease the allowance by
     * @return True if the operation succeeded
     */
    function decreaseAllowance(address spender, uint256 subtractedValue) external returns (bool) {
        address owner = _msgSender();
        uint256 currentAllowance = allowance(owner, spender);

        if (currentAllowance < subtractedValue) {
            revert ERC20InsufficientAllowance(spender, currentAllowance, subtractedValue);
        }

        _approve(owner, spender, currentAllowance - subtractedValue);
        return true;
    }

    /**
     * @notice Pause token transfers
     */
    function pause() external onlyRole(PAUSE_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause token transfers
     */
    function unpause() external onlyRole(PAUSE_ROLE) {
        _unpause();
    }

    /**
     * @notice Set issue cap
     * @param newCap New maximum supply (0 = unlimited)
     */
    function setIssueCap(uint256 newCap) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (newCap != 0 && newCap < totalSupply()) revert CapBelowSupply();

        uint256 oldCap = issueCap;
        issueCap = newCap;

        emit IssueCapUpdated(oldCap, newCap);
    }

    /**
     * @notice Set or rotate the KycManager. Pass address(0) to flip to permissionless mode.
     */
    function setKycManager(address newManager) external onlyRole(DEFAULT_ADMIN_ROLE) {
        address old = kycManager;
        kycManager = newManager;
        emit KycManagerUpdated(old, newManager);
    }

    /**
     * @notice Ban an account
     * @param account The address to ban
     */
    function _banAccount(address account) private {
        if (isBanned(account)) revert InvalidBannedAccount(account);

        _bannedList[account] = true;
        emit AccountBanned(account);
    }

    /**
     * @notice Unban an account
     * @param account The address to unban
     */
    function _unbanAccount(address account) private {
        if (!isBanned(account)) revert InvalidBannedAccount(account);

        _bannedList[account] = false;
        emit AccountUnbanned(account);
    }

    /**
     * @notice Ban multiple accounts at once
     * @param addresses An array of addresses to be banned
     * @dev Maximum batch size is 100 addresses to prevent gas limit issues
     */
    function banAddresses(address[] calldata addresses) external onlyRole(BANLIST_ROLE) {
        uint256 length = addresses.length;

        for (uint256 i; i < length; ) {
            _banAccount(addresses[i]);
            unchecked {
                ++i;
            }
        }
    }

    /**
     * @notice Unban multiple accounts at once
     * @param addresses An array of addresses to be unbanned
     * @dev Maximum batch size is 100 addresses to prevent gas limit issues
     */
    function unbanAddresses(address[] calldata addresses) external onlyRole(BANLIST_ROLE) {
        uint256 length = addresses.length;

        for (uint256 i; i < length; ) {
            _unbanAccount(addresses[i]);
            unchecked {
                ++i;
            }
        }
    }

    /**
     * @notice Check if an account is banned
     * @param account The address to check
     * @return True if the account is banned
     */
    function isBanned(address account) public view returns (bool) {
        return _bannedList[account];
    }

    /**
     * @notice Override _update to add ban check, KYC check, and pause check
     * @dev Called on mint, burn, and transfer
     * @dev Ban checks apply to ALL operations including mint and burn for regulatory compliance
     * @dev KYC gate runs only when kycManager != address(0) (permissioned mode)
     * @dev Pause check handled by ERC20PausableUpgradeable parent
     */
    function _update(
        address from,
        address to,
        uint256 amount
    ) internal override(ERC20Upgradeable, ERC20PausableUpgradeable) {
        // Check sender ban status (including burns FROM banned addresses)
        if (from != address(0) && isBanned(from)) {
            revert BannedSender(from);
        }
        // Check recipient ban status (including mints TO banned addresses)
        if (to != address(0) && isBanned(to)) {
            revert BannedRecipient(to);
        }

        // KYC gate (permissionless when kycManager == address(0))
        address mgr = kycManager;
        if (mgr != address(0)) {
            if (from != address(0) && !IKycManager(mgr).isKyced(from)) revert NotKyced(from);
            if (to != address(0) && !IKycManager(mgr).isKyced(to)) revert NotKyced(to);
        }

        // Pause check is handled by super._update() via ERC20PausableUpgradeable
        super._update(from, to, amount);
    }

    function _authorizeUpgrade(address newImplementation) internal view override onlyRole(UPGRADE_ROLE) {
        if (newImplementation == address(0)) revert InvalidAddress();
    }

    function version() external pure returns (string memory) {
        return "1.0.0";
    }

    /**
     * @dev This empty reserved space is put in place to allow future versions to add new
     * variables without shifting down storage in the inheritance chain.
     * See https://docs.openzeppelin.com/contracts/4.x/upgradeable#storage_gaps
     */
    uint256[44] private __gap;
}

contracts/extension/AssetRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { UUPSUpgradeable } from "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";
import { Ownable2StepUpgradeable } from "@openzeppelin/contracts-upgradeable/access/Ownable2StepUpgradeable.sol";

import { IERC20Metadata } from "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import { Math } from "@openzeppelin/contracts/utils/math/Math.sol";
import "../interfaces/IAssetRegistry.sol";
import "../interfaces/IPriceFeed.sol";

/**
 * @title AssetRegistry
 * @notice Simple registry for managing supported underlying assets with price oracles
 */
contract AssetRegistry is IAssetRegistry, UUPSUpgradeable, Ownable2StepUpgradeable {
    using Math for uint256;

    // Custom errors
    error AssetRegistryZeroAddress();
    error AssetRegistryInvalidStalePeriod(uint256 stalePeriod);
    error AssetRegistryAssetNotSupported(address asset);
    error AssetRegistryInvalidPrice(int256 price);
    error AssetRegistryInvalidAssetDecimals(uint8 decimals);
    error AssetRegistryStalePriceData(uint256 updatedAt, uint256 currentTime, uint256 maxStale);
    error AssetRegistryUnsupportedAssetConfiguration();

    // Constants
    uint256 private constant DECIMALS = 18;

    // Asset configurations
    mapping(address => AssetConfig) private _assetConfigs;
    address[] private _supportedAssets;
    mapping(address => uint256) private _assetIndex;

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    function initialize(address _owner) external initializer {
        __Ownable_init(_owner);
        __Ownable2Step_init();
    }

    function _authorizeUpgrade(address) internal override onlyOwner {}

    /**
     * @notice Get fresh price from price feed with staleness check
     * @param asset The asset address to get the staleness period for
     * @param priceFeed The price feed address
     * @return price The fresh price
     * @return decimals The price feed decimals
     */
    function _getFreshPrice(address asset, address priceFeed) internal view returns (uint256 price, uint8 decimals) {
        (uint80 roundId, int256 answer, , uint256 updatedAt, uint80 answeredInRound) = IPriceFeed(priceFeed)
            .latestRoundData();

        if (answer <= 0) revert AssetRegistryInvalidPrice(answer);

        uint256 assetMaxStalePeriod = _assetConfigs[asset].maxStalePeriod;
        if (block.timestamp - updatedAt > assetMaxStalePeriod) {
            revert AssetRegistryStalePriceData(updatedAt, block.timestamp, assetMaxStalePeriod);
        }

        // Check for incomplete round data
        if (answeredInRound < roundId) {
            revert AssetRegistryStalePriceData(updatedAt, block.timestamp, assetMaxStalePeriod);
        }

        price = uint256(answer);
        decimals = IPriceFeed(priceFeed).decimals();
    }

    function setAssetConfig(AssetConfig calldata config) external onlyOwner {
        address asset = config.asset;
        if (asset == address(0)) revert AssetRegistryZeroAddress();

        uint8 assetDecimals = IERC20Metadata(asset).decimals();
        if (assetDecimals > DECIMALS) {
            revert AssetRegistryInvalidAssetDecimals(assetDecimals);
        }

        if (config.priceFeed != address(0) && config.maxStalePeriod == 0) {
            revert AssetRegistryInvalidStalePeriod(config.maxStalePeriod);
        }

        bool wasSupported = _assetConfigs[asset].isSupported;
        _assetConfigs[asset] = config;

        if (config.isSupported && !wasSupported) {
            _supportedAssets.push(asset);
            _assetIndex[asset] = _supportedAssets.length - 1;
            emit AssetAdded(asset, config);
        } else if (config.isSupported && wasSupported) {
            emit AssetUpdated(asset, config);
        } else {
            revert AssetRegistryUnsupportedAssetConfiguration();
        }
    }

    function removeAsset(address asset) external onlyOwner {
        if (!_assetConfigs[asset].isSupported) revert AssetRegistryAssetNotSupported(asset);

        _assetConfigs[asset].isSupported = false;
        _removeAssetFromArray(asset);
        emit AssetRemoved(asset);
    }

    function getAssetConfig(address asset) external view returns (AssetConfig memory config) {
        return _assetConfigs[asset];
    }

    function isAssetSupported(address asset) external view returns (bool supported) {
        return _assetConfigs[asset].isSupported;
    }

    function convertFromUnderlying(address _asset, uint256 _amount) external view returns (uint256 amount) {
        AssetConfig memory config = _assetConfigs[_asset];
        if (!config.isSupported) revert AssetRegistryAssetNotSupported(_asset);

        uint256 amount1 = _amount;
        uint8 assetDecimals = IERC20Metadata(_asset).decimals();

        // If asset has price feed, convert to USD value first
        if (config.priceFeed != address(0)) {
            (uint256 rate, uint8 feedDecimals) = _getFreshPrice(_asset, config.priceFeed);
            amount1 = _amount.mulDiv(rate, 10 ** feedDecimals);
        }

        // Scale to 18 decimals
        amount = amount1 * (10 ** (DECIMALS - assetDecimals));
    }

    function convertToUnderlying(address _asset, uint256 _amount) external view returns (uint256 amount) {
        AssetConfig memory config = _assetConfigs[_asset];
        if (!config.isSupported) revert AssetRegistryAssetNotSupported(_asset);

        uint8 assetDecimals = IERC20Metadata(_asset).decimals();

        // Scale down from 18 decimals to asset decimals with proper rounding
        uint256 divisor = 10 ** (DECIMALS - assetDecimals);
        uint256 amount1 = _amount.mulDiv(1, divisor, Math.Rounding.Floor);

        // If asset has price feed, convert from USD value
        if (config.priceFeed != address(0)) {
            (uint256 rate, uint8 feedDecimals) = _getFreshPrice(_asset, config.priceFeed);
            amount = amount1.mulDiv(10 ** feedDecimals, rate);
        } else {
            amount = amount1;
        }
    }

    function getSupportedAssets() external view returns (address[] memory assets) {
        return _supportedAssets;
    }

    function _removeAssetFromArray(address asset) internal {
        uint256 index = _assetIndex[asset];
        uint256 lastIndex = _supportedAssets.length - 1;

        if (index != lastIndex) {
            address lastAsset = _supportedAssets[lastIndex];
            _supportedAssets[index] = lastAsset;
            _assetIndex[lastAsset] = index;
        }

        _supportedAssets.pop();
        delete _assetIndex[asset];
    }

    /**
     * @dev This empty reserved space is put in place to allow future versions to add new
     * variables without shifting down storage in the inheritance chain.
     * See https://docs.openzeppelin.com/contracts/4.x/upgradeable#storage_gaps
     */
    uint256[50] private __gap;
}

contracts/extension/DepositRedeemLimiter.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

struct DepositRedeemLimiterCfg {
    uint256 depositMinimum;
    uint256 redeemMinimum;
    uint256 firstDepositAmount;
}

/**
 * @title DepositRedeemLimiter
 * @notice contract implementing minimum thresholds for depositing and redeeming.
 */
abstract contract DepositRedeemLimiter {
    uint256 public depositMinimum;
    uint256 public redeemMinimum;
    uint256 public firstDepositAmount;

    event DepositMinimumUpdated(uint256 newMinimum);
    event RedeemMinimumUpdated(uint256 newMinimum);
    event FirstDepositAmount(uint256 amount);
    error DepositLessThanMinimum(uint256 amount, uint256 minimum);
    error RedeemLessThanMinimum(uint256 amount, uint256 minimum);

    /**
     * @notice Initializes deposit and redeem minimums.
     * @param _depositMinimum    Min amount allowed to deposit in one transaction (in token decimals - 18)
     * @param _redeemMinimum  Min amount allowed to redeem in one transaction (in token decimals - 18)
     * @param _firstDepositAmount The first deposit amount (in token decimals - 18)
     */

    function __DepositRedeemLimiter_init(
        uint256 _depositMinimum,
        uint256 _redeemMinimum,
        uint256 _firstDepositAmount
    ) internal {
        depositMinimum = _depositMinimum;
        redeemMinimum = _redeemMinimum;
        firstDepositAmount = _firstDepositAmount;
    }

    /*//////////////////////////////////////////////////////////////
                          Deposit Functions
    //////////////////////////////////////////////////////////////*/
    /**
     * @dev Updates the deposit minimum.
     * @dev Amount should be in token decimals (18) for accurate comparison across different underlying assets
     * @param _depositMinimum New deposit minimum in token equivalent.
     */
    function _setDepositMinimum(uint256 _depositMinimum) internal {
        depositMinimum = _depositMinimum;
        emit DepositMinimumUpdated(_depositMinimum);
    }

    /**
     * @dev Updates the redeem minimum.
     * @param _redeemMinimum New redeem minimum.
     */
    function _setRedeemMinimum(uint256 _redeemMinimum) internal {
        redeemMinimum = _redeemMinimum;
        emit RedeemMinimumUpdated(_redeemMinimum);
    }

    /**
     * @notice Set the first deposit amount
     * @dev Amount should be in token decimals (18) for accurate comparison across different underlying assets
     * @param _amount The first deposit amount in token equivalent
     */
    function _setFirstDepositAmount(uint256 _amount) internal {
        firstDepositAmount = _amount;
        emit FirstDepositAmount(_amount);
    }

    uint256[10] private __gap;
}

